import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { ShoppingCart, Bell, Menu, X, ChevronDown, User, LogOut, Dumbbell } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';
import API from '../utils/api';

const navLinks = [
  { label: 'Home',            path: '/' },
  { label: 'Exercises',       path: '/exercises' },
  { label: 'Diet Plans',      path: '/diet' },
  { label: 'Transformations', path: '/transformations' },
  { label: 'Store',           path: '/store' },
  { label: 'About',           path: '/about' },
  { label: 'Enquiry',         path: '/enquiry' },
];

export default function Navbar() {
  const { user, logout } = useAuth();
  const { count } = useCart();
  const navigate = useNavigate();
  const location = useLocation();
  const [open, setOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [unread, setUnread] = useState(0);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    if (user) {
      API.get('/notifications').then(res => {
        setUnread(res.data.filter(n => !n.isRead).length);
      }).catch(() => {});
    }
  }, [user, location]);

  const handleLogout = () => { logout(); navigate('/'); };

  return (
    <motion.nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        scrolled ? 'bg-[#0a0a0f]/95 backdrop-blur-md shadow-lg shadow-orange-500/10' : 'bg-transparent'
      }`}
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.5 }}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          {/* Logo */}
          <Link to="/" className="flex items-center gap-2 group">
            <div className="w-9 h-9 bg-gradient-to-br from-orange-500 to-red-500 rounded-lg flex items-center justify-center">
              <Dumbbell size={20} className="text-white" />
            </div>
            <div className="flex flex-col leading-none">
              <span className="text-white font-black text-lg tracking-wider gym-font">FITNESSBY</span>
              <span className="text-orange-500 font-bold text-xs tracking-widest">AJEET</span>
            </div>
          </Link>

          {/* Desktop Nav */}
          <div className="hidden lg:flex items-center gap-1">
            {navLinks.map(link => (
              <Link
                key={link.path}
                to={link.path}
                className={`px-3 py-2 rounded-lg text-sm font-medium transition-all duration-200 ${
                  location.pathname === link.path
                    ? 'text-orange-500 bg-orange-500/10'
                    : 'text-gray-300 hover:text-orange-400 hover:bg-white/5'
                }`}
              >
                {link.label}
              </Link>
            ))}
          </div>

          {/* Right Side */}
          <div className="hidden lg:flex items-center gap-3">
            {/* Cart */}
            <Link to="/cart" className="relative p-2 rounded-lg text-gray-300 hover:text-orange-400 hover:bg-white/5 transition-all">
              <ShoppingCart size={20} />
              {count > 0 && (
                <span className="absolute -top-1 -right-1 bg-orange-500 text-white text-xs rounded-full w-5 h-5 flex items-center justify-center font-bold">{count}</span>
              )}
            </Link>

            {user ? (
              <>
                {/* Notifications */}
                <Link to="/notifications" className="relative p-2 rounded-lg text-gray-300 hover:text-orange-400 hover:bg-white/5 transition-all">
                  <Bell size={20} />
                  {unread > 0 && (
                    <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs rounded-full w-5 h-5 flex items-center justify-center font-bold">{unread}</span>
                  )}
                </Link>

                {/* User menu */}
                <div className="flex items-center gap-2 ml-2">
                  <div className="w-8 h-8 rounded-full bg-gradient-to-br from-orange-500 to-red-500 flex items-center justify-center text-white font-bold text-sm">
                    {user.name?.[0]?.toUpperCase()}
                  </div>
                  <div className="flex flex-col leading-none">
                    <span className="text-white text-xs font-semibold">{user.name}</span>
                    <span className="text-orange-400 text-xs capitalize">{user.role}</span>
                  </div>
                </div>
                {user.role === 'admin' && (
                  <Link to="/admin" className="btn-fire text-sm px-4 py-2">Admin</Link>
                )}
                {user.role === 'member' && (
                  <Link to="/dashboard" className="btn-fire text-sm px-4 py-2">Dashboard</Link>
                )}
                <button onClick={handleLogout} className="p-2 rounded-lg text-gray-400 hover:text-red-400 hover:bg-white/5 transition-all">
                  <LogOut size={18} />
                </button>
              </>
            ) : (
              <Link to="/login" className="btn-fire text-sm px-4 py-2">Login</Link>
            )}
          </div>

          {/* Mobile menu button */}
          <button
            className="lg:hidden p-2 rounded-lg text-gray-300 hover:text-orange-400"
            onClick={() => setOpen(!open)}
          >
            {open ? <X size={22} /> : <Menu size={22} />}
          </button>
        </div>
      </div>

      {/* Mobile menu */}
      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="lg:hidden bg-[#0a0a0f]/98 backdrop-blur-md border-t border-white/10"
          >
            <div className="px-4 py-4 flex flex-col gap-2">
              {navLinks.map(link => (
                <Link
                  key={link.path}
                  to={link.path}
                  onClick={() => setOpen(false)}
                  className={`px-4 py-3 rounded-lg text-sm font-medium ${
                    location.pathname === link.path
                      ? 'text-orange-500 bg-orange-500/10'
                      : 'text-gray-300'
                  }`}
                >
                  {link.label}
                </Link>
              ))}
              <div className="flex gap-3 mt-2">
                <Link to="/cart" onClick={() => setOpen(false)} className="flex items-center gap-2 text-gray-300">
                  <ShoppingCart size={18} /> Cart {count > 0 && `(${count})`}
                </Link>
              </div>
              {user ? (
                <button onClick={() => { handleLogout(); setOpen(false); }} className="text-red-400 text-left px-4 py-2 flex items-center gap-2">
                  <LogOut size={18} /> Logout
                </button>
              ) : (
                <Link to="/login" onClick={() => setOpen(false)} className="btn-fire text-center py-3">Login</Link>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.nav>
  );
}
